function o(t,r=2){return t==null?"--":`${t>=0?"+":""}${(t*100).toFixed(r)}%`}function f(t,r=2){return t==null?"--":t.toFixed(r)}function u(t,r=!0){if(!t)return"--";const n=new Date(t),e=n.toLocaleDateString("zh-CN",{year:"numeric",month:"2-digit",day:"2-digit"});if(!r)return e;const i=n.toLocaleTimeString("zh-CN",{hour:"2-digit",minute:"2-digit"});return`${e} ${i}`}function s(t){if(!t)return"--";const r=Date.now()-new Date(t).getTime(),n=Math.floor(r/6e4);if(n<1)return"刚刚";if(n<60)return`${n} 分钟前`;const e=Math.floor(n/60);return e<24?`${e} 小时前`:`${Math.floor(e/24)} 天前`}function a(t,r=1){return t==null?"--":`${(t*100).toFixed(r)}%`}function c(t){return t==null||t===0?"text-muted":t>0?"text-success":"text-danger"}export{s as a,u as b,f as c,o as d,a as f,c as g};
